+fn summarize_latency(latencies: &[Option<LatencySummary>]) -> LatencySummary {
+    let collected = latencies
+        .iter()
+        .filter_map(Option::as_ref)
+        .collect::<Vec<_>>();
+    if collected.is_empty() {
+        return zero_latency_summary();
