+        .iter()
+        .map(|latency| latency.p50)
+        .collect::<Vec<_>>();
+    let p95 = collected
+        .iter()
+        .map(|latency| latency.p95)
+        .collect::<Vec<_>>();
+    let p99 = collected
+        .iter()
+        .map(|latency| latency.p99)
+        .collect::<Vec<_>>();
+
+    LatencySummary {
+        p50: percentile_f64(&p50, 50),
+        p95: percentile_f64(&p95, 95),
+        p99: percentile_f64(&p99, 99),
+    }
